      const t = e.target;
      if (!t || (t.closest && t.closest('#eon-layer, #eon-pockets, #eon-bag, #eon-ask, #eon-ask-chip, #eon-tools-menu, #eon-magnify'))) return;
      const text = (t.innerText || t.textContent || '').replace(/\s+/g, ' ').trim();
      if (!text) return;
      e.preventDefault(); e.stopPropagation();
