    if (/[a-z]/i.test(p.text)) { add('AA  UPPERCASE', () => this._recase(p, 'upper')); add('aa  lowercase', () => this._recase(p, 'lower')); add('Aa  Title Case', () => this._recase(p, 'title')); }
