function answerBrain(q) {
  const nq = String(q || '').toLowerCase();
  for (const item of QA) { if (item.re.test(nq)) { const a = item.a[Math.floor(Math.random() * item.a.length)]; return { speak: a, detail: item.d || null, source: 'brain-qa' }; } }
  return null;
}
const EonBrainQA = { answerBrain, size: QA.length };
if (typeof window !== 'undefined') window.EonBrainQA = Object.assign(window.EonBrainQA || {}, EonBrainQA);
